            <Route path={ROUTES.KPIS} element={<KpisPage />} />
            <Route path={ROUTES.PROFILE} element={<ProfilePage />} />
          </Route>

          <Route path={ROUTES.NOT_FOUND} element={<NotFoundPage />} />
        </Routes>
      </Suspense>
    </BrowserRouter>
  );
}

export default AppRouter;
