                        {sprint.completed_points} / {sprint.planned_capacity}
                      </span>
                      <span className="text-xs text-muted-foreground">
                        {percent(sprint)}
                      </span>
                    </div>
                  </td>
                  <td className="px-4 py-3">
                    <div className="flex items-center justify-end gap-1">
                      {canStart && (
                        <Button
                          type="button"
                          variant="ghost"
