                      )}
                      <Button
                        type="button"
                        variant="ghost"
                        size="icon"
                        aria-label={`Edit ${sprint.name}`}
                        onClick={() => onEdit(sprint)}
                        disabled={isMutating || !canEdit}
                        title="Edit sprint"
                      >
                        <Pencil className="h-4 w-4" />
                      </Button>
                      <Button
                        type="button"
                        variant="ghost"
