              Planned capacity: {sprint.planned_capacity}
            </p>
          )}
          {errors.completed_points && (
            <p className="text-xs text-destructive">
              {errors.completed_points.message}
            </p>
          )}
        </div>

        <div className="flex items-center justify-end gap-2 pt-2">
