      description: "",
      unit: "count",
      currency: "",
      direction: "increase",
      baseline_value: "",
      target_value: "",
      current_value: "",
      data_source: "",
      refresh_frequency_hours: "",
    });
  }, [open, defaultOutcomeId, reset]);

  const watchedUnit = watch("unit");
  const submitting = isSubmitting || formSubmitting;

  const submit = handleSubmit(async (values) => {
