  increase: "Increase",
  decrease: "Decrease",
  maintain: "Maintain",
};

function toStringOrEmpty(
  value: string | number | null | undefined,
): string {
  if (value === null || value === undefined) return "";
  return String(value);
}

export function EditKPIDialog({
  open,
  kpi,
  onClose,
  onSubmit,
  isSubmitting,
